const src=($json.body&&typeof $json.body==='object')?$json.body:($json.query||$json||{});
const raw=src.days!=null?src.days:7;
const days=Math.min(60,Math.max(1,parseInt(raw,10)||7));
return [{json:{days}}];

const ctx=$json.ctx;
const days=$('Normalize input').first().json.days;
const rules='You are tnAI, the weekly analyst for the Managing Director of Tecknuovo, a UK digital-delivery consultancy. This brief covers THE LAST '+days+' DAYS. The dashboard BELOW your brief already shows the detail: per-account risk stories, potential risks forming, and opportunity heat. YOUR BRIEF IS THE EXECUTIVE SUMMARY OF THAT PICTURE - what she absorbs in thirty seconds before deciding where to scroll. PERSPECTIVE: she thinks zoomed out; never day-to-day detail; always name accounts; compare with the previous '+days+'-day period where the data allows. SECTION RULES: whats_happening = a 1-2 sentence overview that states a VERDICT with at least one number (e.g. how many accounts are healthy vs at risk, or the biggest movement of the period) - BANNED openers: \'a mix of risks and opportunities\', \'notable progress\', or any sentence that could describe any week at any company. points = an ARRAY of 3-5 strings, one specific insight each: the macro risk picture with accounts named, emerging concerns with a clause on WHY each matters, AND where the commercial energy is gathering. BALANCE RULE: if there are opportunity signals or open deals in the data, at least ONE point MUST be about the commercial upside, naming the account and the money (use top_open_deals). A brief that only talks about risk is a FAILED brief - she runs a business, not a risk register. Every point must carry an account name, a number or a movement - never a platitude. Do NOT recite call volumes or activity counts - use a number only when it changes the meaning (money, the age of an unresolved risk, a big swing). why = 2-3 sentences on the pattern behind the period, stated as CAUSAL claims naming accounts (X is happening because Y, seen at A and B). BANNED: abstract filler like \'highlights the interconnected nature of\' or \'underscores the importance of\'. accounts = an ARRAY of 3-6 objects, one per account that MATTERED this period, most important first - and NOT only troubled ones: include at least one account whose story this period is opportunity or momentum (a big open deal moving, opportunity signals landing) whenever the data has one: {"name": the account name exactly as it appears in the data, "update": 2-3 sentences on what actually happened there this period, "why": 1-2 sentences on WHY it matters or what is driving it, stated as a causal claim - this is the reasoning that sits directly under that account, "actions": 0-2 short imperative suggested actions for leadership (empty array if none)}. The update and why must carry NEW information, not restate the macro points. needs_you = at most 3 items that GENUINELY need a managing director: critical risks, account/relationship risks, anything unresolved 14+ days (state its age in days). For NEW risks say \'new this week\' instead of quoting an age of zero, or a commercial move worth her weight. Empty array if nothing qualifies - never pad. STYLE: plain UK business English, no jargon, no flattery, no hedging. Never use em dashes; use commas or hyphens. Return ONLY JSON: {"whats_happening":"the 1-2 sentence overview","points":["..."],"why":"...","accounts":[{"name":"...","update":"...","why":"...","actions":["..."]}],"needs_you":["..."]}';
const prompt=rules+'\n\nTHE DATA (past '+days+' days unless stated):\n'+JSON.stringify(ctx);
return [{json:{prompt}}];

const raw=($json.text||$json.response||$json.output||'').trim();
const days=$('Normalize input').first().json.days;
function parseModelJson(t){
  const m=t.match(/\{[\s\S]*\}/); if(!m){return null;}
  let s=m[0];
  try{return JSON.parse(s);}catch(e){}
  let out='',inStr=false,esc=false;
  for(const ch of s){
    if(esc){out+=ch;esc=false;continue;}
    if(ch==='\\'){out+=ch;esc=true;continue;}
    if(ch==='"'){inStr=!inStr;out+=ch;continue;}
    if(inStr&&ch==='\n'){out+='\\n';continue;}
    if(inStr&&ch==='\r'){continue;}
    if(inStr&&ch==='\t'){out+='\\t';continue;}
    out+=ch;
  }
  try{return JSON.parse(out);}catch(e){return null;}
}
const obj=parseModelJson(raw);
if(!obj){return [{json:{sql:"SELECT 'model output could not be parsed' AS note", parse_error:true, raw_head:raw.slice(0,300)}}];}
const arr=function(v,n){return Array.isArray(v)?v.slice(0,n).map(function(x){return String(x).slice(0,300)}):[]};
const points=Array.isArray(obj.points)?obj.points.slice(0,5).map(function(x){return String(x).slice(0,300)}):[];
const body=String(obj.whats_happening||'').slice(0,600)+(points.length?'\n'+points.map(function(p){return '- '+p}).join('\n'):'');
const accts=Array.isArray(obj.accounts)?obj.accounts.slice(0,6).map(function(a){return {
 name:String((a&&a.name)||'').slice(0,80),
 update:String((a&&a.update)||'').slice(0,700),
 why:String((a&&a.why)||'').slice(0,500),
 actions:Array.isArray(a&&a.actions)?a.actions.slice(0,2).map(function(x){return String(x).slice(0,250)}):[]
};}).filter(function(a){return a.name&&a.update;}):[];
const out={
 whats_happening:body.slice(0,2000),
 why:String(obj.why||'').slice(0,1200),
 accounts:accts,
 watch_for:arr(obj.watch_for,3),
 needs_you:arr(obj.needs_you,3)
};
if(!out.whats_happening){return [{json:{sql:"SELECT 'empty brief - not saved' AS note", parse_error:true}}];}
const e=function(s){return String(s).replace(/'/g,"''")};
const sql="INSERT INTO briefs (audience,period_start,period_end,content) VALUES ('leadership', now()::date - "+days+", now()::date, '"+e(JSON.stringify(out))+"'::jsonb);";
return [{json:{sql,preview:out,days:days}}];
